 import re

def is_valid_email(email):
    regex = '^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$'
    if re.search(regex, email): 
        return True
    else:  
        return False

email = "example@example.com"
if is_valid_email(email):
    print("Valid Email")
else:
    print("Invalid Email") # Output: Valid Email

